const grouped = {};
for (const item of items) {
  const s = item.json;
  const company = s.company || 'Unknown';
  if (!grouped[company]) grouped[company] = { company, query_id: s.query_id || 'q_001', signals: [], high_relevance_count: 0, medium_relevance_count: 0, job_posting_count: 0, product_signal_count: 0, tech_signal_count: 0 };
  grouped[company].signals.push({ signal_type: s.signal_type, title: s.title, summary: s.summary, detected_skills: s.detected_skills, role_relevance: s.role_relevance, confidence: s.confidence, interpretation: s.interpretation, recommended_ta_action: s.recommended_ta_action, source_url: s.source_url });
  if (s.role_relevance === 'High') grouped[company].high_relevance_count++;
  if (s.role_relevance === 'Medium') grouped[company].medium_relevance_count++;
  if (s.signal_type === 'job_posting') grouped[company].job_posting_count++;
  if (s.signal_type === 'product_news') grouped[company].product_signal_count++;
  if (s.signal_type === 'github' || s.signal_type === 'tech_content') grouped[company].tech_signal_count++;
}
return Object.values(grouped).map((g, index) => ({ json: { pool_id: `pool_${String(index+1).padStart(3,'0')}`, ...g }}));

