return items.map((item, index) => {
  const base = $items('Parse Candidate JSON')[index].json;
  let raw = item.json.choices?.[0]?.message?.content || item.json.message?.content || item.json.output_text || item.json.text || '';
  raw = raw.replace(/```json/g, '').replace(/```/g, '').trim();
  let p;
  try { p = JSON.parse(raw); } catch(e) {
    const tenure = Number(base.tenure_years_current_company || 0);
    const score = Math.min(95, 55 + tenure * 8 + (String(base.public_activity_level).toLowerCase() === 'low' ? 8 : 0));
    p = { candidate_name: base.candidate_name, inferred_seniority: score >= 80 ? 'Senior' : 'Mid', latent_seniority_score: score, tenure_signal: `${tenure || 'Unknown'} years in current company may indicate accumulated expertise.`, profile_freshness_signal: `Public activity level: ${base.public_activity_level || 'Unknown'}.`, company_environment_signal: `${base.current_company} is a relevant environment for AI/product engineering talent.`, mobility_signal: score >= 78 ? 'Reach out now' : 'Watch', seniority_reasoning: 'Latent seniority inferred from tenure, company context and role adjacency. Validate manually before outreach.', recommended_approach_timing: score >= 78 ? 'Now' : 'Watchlist', outreach_angle: base.personalized_outreach_angle || 'Production AI at marketplace scale.' };
  }
  return { json: {
    ...base,
    inferred_seniority: p.inferred_seniority || 'Unclear',
    latent_seniority_score: p.latent_seniority_score || 0,
    tenure_signal: p.tenure_signal || '',
    profile_freshness_signal: p.profile_freshness_signal || '',
    company_environment_signal: p.company_environment_signal || '',
    mobility_signal: p.mobility_signal || 'Watch',
    seniority_reasoning: p.seniority_reasoning || '',
    recommended_approach_timing: p.recommended_approach_timing || 'Watchlist',
    latent_outreach_angle: p.outreach_angle || '',
    created_at: new Date().toISOString().slice(0,10)
  }};
});
